'use client'

import { useRef, useState, useEffect } from 'react'
import Link from 'next/link'
import {
  motion,
  useScroll,
  useTransform,
  useReducedMotion,
} from 'framer-motion'

const EW = 500   // envelope width  (desktop)
const EH = 330   // envelope height (desktop)
const MEW = 340  // envelope width  (mobile)
const MEH = 226  // envelope height (mobile)

// ─── wax seal ──────────────────────────────────────────────────────────────────
function WaxSeal({
  size = 56,
  onClick,
  label = 'Open',
}: {
  size?: number
  onClick?: () => void
  label?: string
}) {
  return (
    <button
      onClick={onClick}
      className={`rounded-full flex items-center justify-center ${onClick ? 'cursor-pointer' : 'cursor-default pointer-events-none'}`}
      style={{ width: size, height: size, background: '#8B4B35', boxShadow: '0 4px 20px rgba(139,75,53,0.38)' }}
      aria-label={label}
      type="button"
    >
      <svg width={size * 0.44} height={size * 0.44} viewBox="0 0 26 26" fill="none" aria-hidden="true">
        <path
          d="M13 2L15.6 9.2L23 9.7L17.5 14.4L19.4 21.6L13 17.8L6.6 21.6L8.5 14.4L3 9.7L10.4 9.2L13 2Z"
          fill="#F5D4BC"
          fillOpacity="0.75"
        />
      </svg>
    </button>
  )
}

// ─── card face ─────────────────────────────────────────────────────────────────
function CardFace({ names, small = false }: { names: string; small?: boolean }) {
  return (
    <div
      className="absolute inset-0 flex flex-col items-center justify-center gap-0"
      style={{ background: '#FAF6F0' }}
    >
      <span
        className="font-inter uppercase"
        style={{ fontSize: small ? 7 : 9, letterSpacing: '0.3em', color: 'rgba(26,26,26,0.3)' }}
      >
        You are invited
      </span>
      <div
        className="font-cormorant font-light text-center leading-none mt-3"
        style={{
          fontSize: small ? 'clamp(1rem, 5vw, 1.4rem)' : 'clamp(1.5rem, 4vw, 2.1rem)',
          color: '#1A1A1A',
        }}
      >
        {names}
      </div>
      <div className="mt-4 w-10 h-px" style={{ background: 'rgba(26,26,26,0.14)' }} />
      <span
        className="font-inter uppercase mt-3"
        style={{ fontSize: small ? 7 : 8, letterSpacing: '0.28em', color: 'rgba(26,26,26,0.25)' }}
      >
        Wedding Celebration
      </span>
    </div>
  )
}

// ─── fold lines ────────────────────────────────────────────────────────────────
function FoldLines({ w, h }: { w: number; h: number }) {
  return (
    <svg
      className="absolute inset-0 w-full h-full pointer-events-none"
      viewBox={`0 0 ${w} ${h}`}
      aria-hidden="true"
    >
      <line x1="0"   y1="0"  x2={w / 2} y2={h / 2} stroke="#C4B09A" strokeWidth="0.8" />
      <line x1={w}   y1="0"  x2={w / 2} y2={h / 2} stroke="#C4B09A" strokeWidth="0.8" />
      <line x1="0"   y1={h}  x2={w / 2} y2={h / 2} stroke="#C4B09A" strokeWidth="0.8" />
      <line x1={w}   y1={h}  x2={w / 2} y2={h / 2} stroke="#C4B09A" strokeWidth="0.8" />
    </svg>
  )
}

// ─── names input + CTA ─────────────────────────────────────────────────────────
function NamesInput({
  names,
  setNames,
  className = '',
}: {
  names: string
  setNames: (v: string) => void
  className?: string
}) {
  return (
    <div className={`flex flex-col items-center gap-5 ${className}`}>
      <input
        type="text"
        value={names}
        onChange={(e) => setNames(e.target.value)}
        placeholder="Type your names."
        maxLength={60}
        className="
          w-64 pb-2 text-center font-cormorant text-2xl font-light
          bg-transparent border-0 border-b
          focus:outline-none
          transition-colors duration-300
        "
        style={{
          color: '#1A1A1A',
          borderBottomColor: 'rgba(26,26,26,0.2)',
          caretColor: '#8B4B35',
        }}
        aria-label="Enter your names"
      />
      <Link
        href="/builder"
        className="
          font-inter text-[11px] tracking-[0.22em] uppercase
          border
          hover:bg-[#1A1A1A] hover:text-white hover:border-[#1A1A1A]
          px-10 py-3.5 rounded-full
          transition-all duration-500
          focus:outline-none focus-visible:ring-1 focus-visible:ring-[#1A1A1A]/25
        "
        style={{ color: 'rgba(26,26,26,0.45)', borderColor: 'rgba(26,26,26,0.18)' }}
      >
        Create yours
      </Link>
    </div>
  )
}

// ─── mobile envelope (tap-to-open) ─────────────────────────────────────────────
function MobileEnvelope({
  names,
  rawNames,
  setNames,
}: {
  names: string
  rawNames: string
  setNames: (v: string) => void
}) {
  const [phase, setPhase] = useState(0)

  const open = () => {
    if (phase > 0) return
    setPhase(1)
    setTimeout(() => setPhase(2), 700)
    setTimeout(() => setPhase(3), 1350)
  }

  const sealGone  = phase >= 1
  const flapOpen  = phase >= 1
  const cardRisen = phase >= 2
  const ctaShown  = phase >= 3

  return (
    <section
      id="envelope"
      className="py-20 flex flex-col items-center gap-10 px-6 min-h-[80dvh] justify-center"
      style={{ background: '#F5EEE6' }}
      aria-label="Interactive envelope"
    >
      {/* Hint */}
      <motion.p
        animate={{ opacity: phase === 0 ? 1 : 0 }}
        transition={{ duration: 0.4 }}
        className="font-inter text-[10px] tracking-[0.25em] uppercase pointer-events-none"
        style={{ color: 'rgba(26,26,26,0.3)' }}
        aria-live="polite"
      >
        Tap the seal to open
      </motion.p>

      {/* Envelope group */}
      <div
        className="relative"
        style={{ width: MEW, height: MEH + 70 }}
      >
        {/* Body */}
        <div
          className="absolute"
          style={{
            width: MEW,
            height: MEH,
            bottom: 0,
            left: 0,
            background: '#EDE0CC',
            border: '1px solid #D4C0A4',
            overflow: 'visible',
          }}
        >
          <FoldLines w={MEW} h={MEH} />

          {/* Card — overflows upward */}
          <motion.div
            initial={{ y: 0, opacity: 0 }}
            animate={cardRisen ? { y: -MEH * 0.42, opacity: 1 } : { y: 0, opacity: 0 }}
            transition={{ duration: 0.85, ease: [0.22, 1, 0.36, 1] }}
            className="absolute"
            style={{ inset: 10, zIndex: 10 }}
          >
            <CardFace names={names} small />
          </motion.div>
        </div>

        {/* Flap perspective wrapper */}
        <div
          style={{
            position: 'absolute',
            bottom: 0,
            left: 0,
            width: MEW,
            height: MEH,
            perspective: 900,
            perspectiveOrigin: '50% 0%',
            zIndex: 20,
            pointerEvents: 'none',
          }}
        >
          <motion.div
            initial={{ rotateX: 0 }}
            animate={flapOpen ? { rotateX: -185 } : { rotateX: 0 }}
            transition={{ duration: 0.9, ease: [0.22, 1, 0.36, 1] }}
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: MEW,
              height: MEH / 2,
              transformOrigin: '50% 100%',
              clipPath: 'polygon(0 0, 100% 0, 50% 100%)',
              background: 'linear-gradient(180deg, #E8DCC8 0%, #EDE0CC 100%)',
              borderTop: '1px solid #D4C0A4',
            }}
          />
        </div>

        {/* Wax seal */}
        <motion.div
          initial={{ scale: 1, opacity: 1 }}
          animate={sealGone ? { scale: 0.4, opacity: 0 } : {}}
          transition={{ duration: 0.35 }}
          style={{
            position: 'absolute',
            left: MEW / 2,
            bottom: MEH / 2,
            transform: 'translate(-50%, 50%)',
            zIndex: 30,
          }}
        >
          <WaxSeal size={52} onClick={open} label="Tap to open invitation" />
        </motion.div>
      </div>

      {/* Input */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={ctaShown ? { opacity: 1 } : { opacity: 0 }}
        transition={{ duration: 0.7 }}
        aria-hidden={!ctaShown}
      >
        <NamesInput names={rawNames} setNames={setNames} />
      </motion.div>
    </section>
  )
}

// ─── desktop sticky-scroll envelope ────────────────────────────────────────────
function DesktopEnvelope({
  names,
  rawNames,
  setNames,
}: {
  names: string
  rawNames: string
  setNames: (v: string) => void
}) {
  const sectionRef = useRef<HTMLDivElement>(null)

  const { scrollYProgress } = useScroll({
    target:  sectionRef,
    offset:  ['start start', 'end end'],
  })

  // Phase 1: envelope enters
  const envOpacity = useTransform(scrollYProgress, [0, 0.14], [0, 1])
  const envY       = useTransform(scrollYProgress, [0, 0.18], [70, 0])

  // Phase 2: seal breaks
  const sealScale   = useTransform(scrollYProgress, [0.22, 0.33, 0.44], [1, 1.18, 0.2])
  const sealOpacity = useTransform(scrollYProgress, [0.22, 0.44], [1, 0])

  // Phase 3: flap opens
  const flapRotate = useTransform(scrollYProgress, [0.38, 0.64], [0, -185])

  // Phase 4: card rises
  const cardY       = useTransform(scrollYProgress, [0.60, 0.84], [0, -(EH * 0.72)])
  const cardOpacity = useTransform(scrollYProgress, [0.60, 0.70], [0, 1])

  // Phase 5: CTA
  const ctaOpacity = useTransform(scrollYProgress, [0.84, 0.97], [0, 1])

  const scrollHint = useTransform(scrollYProgress, [0, 0.04], [1, 0])

  return (
    <section
      ref={sectionRef}
      id="envelope"
      className="relative h-[200vh]"
      style={{ background: '#F5EEE6' }}
      aria-label="Interactive envelope"
    >
      <div className="sticky top-0 h-[100dvh] flex items-center justify-center overflow-hidden">

        {/* Scroll hint */}
        <motion.div
          style={{ opacity: scrollHint }}
          className="absolute bottom-10 left-1/2 -translate-x-1/2 pointer-events-none"
        >
          <span
            className="font-inter text-[10px] tracking-[0.25em] uppercase"
            style={{ color: 'rgba(26,26,26,0.25)' }}
          >
            Scroll to open
          </span>
        </motion.div>

        {/* Envelope group */}
        <motion.div
          style={{ opacity: envOpacity, y: envY }}
          className="relative"
        >
          {/* Container — overflow visible for card to escape */}
          <div style={{ width: EW, height: EH, position: 'relative', overflow: 'visible' }}>

            {/* Envelope body */}
            <div
              className="absolute"
              style={{ inset: 0, background: '#EDE0CC', border: '1px solid #D4C0A4', overflow: 'visible' }}
            >
              <FoldLines w={EW} h={EH} />
            </div>

            {/* Card */}
            <motion.div
              style={{
                position: 'absolute',
                left: 24,
                right: 24,
                top: 18,
                bottom: 18,
                y: cardY,
                opacity: cardOpacity,
                zIndex: 10,
              }}
            >
              <CardFace names={names} />
            </motion.div>

            {/* Flap perspective wrapper */}
            <div
              style={{
                position: 'absolute',
                inset: 0,
                perspective: 1400,
                perspectiveOrigin: '50% 0%',
                zIndex: 20,
                pointerEvents: 'none',
                overflow: 'visible',
              }}
            >
              <motion.div
                style={{
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  width: EW,
                  height: EH / 2,
                  clipPath: 'polygon(0 0, 100% 0, 50% 100%)',
                  background: 'linear-gradient(180deg, #E2D4BC 0%, #EDE0CC 100%)',
                  border: '1px solid #D4C0A4',
                  transformOrigin: '50% 100%',
                  rotateX: flapRotate,
                  transformStyle: 'preserve-3d',
                }}
              />
            </div>

            {/* Wax seal */}
            <motion.div
              style={{
                position: 'absolute',
                left: EW / 2,
                top: EH / 2,
                x: '-50%',
                y: '-50%',
                zIndex: 30,
                scale: sealScale,
                opacity: sealOpacity,
              }}
            >
              <WaxSeal size={62} label="Wax seal" />
            </motion.div>
          </div>
        </motion.div>

        {/* Names input + CTA */}
        <motion.div
          style={{ opacity: ctaOpacity }}
          className="absolute bottom-14 left-1/2 -translate-x-1/2"
        >
          <NamesInput names={rawNames} setNames={setNames} />
        </motion.div>
      </div>
    </section>
  )
}

// ─── reduced-motion fallback ───────────────────────────────────────────────────
function StaticEnvelope({
  names,
  rawNames,
  setNames,
}: {
  names: string
  rawNames: string
  setNames: (v: string) => void
}) {
  return (
    <section
      id="envelope"
      className="py-32 flex flex-col items-center gap-14 px-6"
      style={{ background: '#F5EEE6' }}
      aria-label="Invitation preview"
    >
      <div
        className="relative"
        style={{ width: 320, height: 212, background: '#EDE0CC', border: '1px solid #D4C0A4' }}
      >
        <FoldLines w={320} h={212} />
        <div className="absolute inset-0" style={{ background: '#FAF6F0', margin: 16 }}>
          <CardFace names={names} />
        </div>
      </div>
      <NamesInput names={rawNames} setNames={setNames} />
    </section>
  )
}

// ─── main export ───────────────────────────────────────────────────────────────
export function EnvelopeSection() {
  const reduced  = useReducedMotion()
  const [isMobile, setIsMobile] = useState(false)
  const [rawNames, setRawNames] = useState('')

  useEffect(() => {
    const check = () => setIsMobile(window.matchMedia('(max-width: 767px)').matches)
    check()
    const mq = window.matchMedia('(max-width: 767px)')
    mq.addEventListener('change', check)
    return () => mq.removeEventListener('change', check)
  }, [])

  const displayNames = rawNames.trim() || 'Emma & James'

  if (reduced) {
    return <StaticEnvelope names={displayNames} rawNames={rawNames} setNames={setRawNames} />
  }

  if (isMobile) {
    return <MobileEnvelope names={displayNames} rawNames={rawNames} setNames={setRawNames} />
  }

  return <DesktopEnvelope names={displayNames} rawNames={rawNames} setNames={setRawNames} />
}
