'use client'

import { useState } from 'react'
import { animate, motion, useMotionValue, useReducedMotion, useTransform } from 'framer-motion'
import type { MotionValue } from 'framer-motion'
import { OpenerProps, hexA, shade, initials } from './shared'
import { RealisticSeal } from './realistic-seal'

function Greeting({ theme, names, fade }: { theme: OpenerProps['theme']; names: string; fade: number | MotionValue<number> }) {
  return (
    <motion.div className="pointer-events-none absolute inset-x-0 top-[12%] z-30 flex flex-col items-center text-center px-6" style={{ opacity: fade }}>
      <p className="font-inter uppercase" style={{ fontSize: 9, letterSpacing: '0.34em', color: 'rgba(255,255,255,0.66)' }}>You are invited</p>
      <p className="mt-3" style={{ fontFamily: theme.font, fontStyle: theme.fontStyle, fontSize: 'clamp(2.1rem, 8vw, 3rem)', color: '#fff', lineHeight: 1.05, textShadow: '0 2px 26px rgba(0,0,0,0.55)' }}>{names}</p>
    </motion.div>
  )
}

function Hint({ label, show, dir }: { label: string; show: boolean; dir: 'down' | 'up' | 'apart' }) {
  const reduced = useReducedMotion()
  const icon = dir === 'up'
    ? <path d="M7.5 12V4M4 7.5l3.5-3.5L11 7.5" stroke="#fff" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round" />
    : dir === 'apart'
    ? <path d="M6 4L3 7.5L6 11M9 4l3 3.5L9 11" stroke="#fff" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round" />
    : <path d="M7.5 3v8M4 7.5l3.5 3.5L11 7.5" stroke="#fff" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round" />
  const bob = reduced ? {} : dir === 'up' ? { y: [0, -7, 0] } : dir === 'apart' ? { scale: [1, 1.08, 1] } : { y: [0, 7, 0] }
  return (
    <motion.div className="pointer-events-none absolute bottom-[8%] left-1/2 z-30 flex -translate-x-1/2 flex-col items-center gap-2"
      animate={{ opacity: show ? 1 : 0 }} transition={{ duration: 0.4 }}>
      <motion.span className="flex items-center justify-center rounded-full"
        style={{ width: 44, height: 44, border: '1px solid rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.08)', backdropFilter: 'blur(4px)' }}
        animate={bob} transition={{ duration: 1.8, repeat: Infinity, ease: 'easeInOut' }}>
        <svg width="15" height="15" viewBox="0 0 15 15" fill="none">{icon}</svg>
      </motion.span>
      <span className="font-inter uppercase" style={{ fontSize: 9, letterSpacing: '0.22em', color: 'rgba(255,255,255,0.75)' }}>{label}</span>
    </motion.div>
  )
}

// ════════════════════════════════════════════════════════════════════════════════
// THE LETTER — a realistic ivory envelope on botanical-embossed paper sealed with
// a photoreal gold wax seal. Click (or drag) the seal: the flap opens, the
// envelope sinks away and the theme film is revealed.
// ════════════════════════════════════════════════════════════════════════════════
export function EnvelopeOpener({ theme, names, onOpen, videoSrc, poster }: OpenerProps) {
  const reduced = useReducedMotion()
  const [opening, setOpening] = useState(false)
  const mono = initials(names)
  const dim = useMotionValue(0.52)
  const ivory = theme.dark ? '#E9E2D2' : '#F4ECDD'

  const finish = () => {
    if (opening) return
    setOpening(true)
    animate(dim, 0, { duration: 0.9, delay: 0.45, ease: [0.4, 0, 0.2, 1] })
    setTimeout(onOpen, 1250)
  }

  return (
    <div className="absolute inset-0 overflow-hidden">
      <FilmBackdropMV videoSrc={videoSrc} poster={poster} dim={dim} />

      {/* the envelope (textured paper) — sinks + fades on open */}
      <motion.div
        className="absolute inset-0"
        animate={opening ? { y: '16%', scale: 1.05, opacity: 0 } : { y: 0, scale: 1, opacity: 1 }}
        transition={{ duration: 0.85, ease: [0.4, 0, 0.2, 1], delay: opening ? 0.4 : 0 }}
        style={{ transformOrigin: '50% 0%' }}
      >
        <BotanicalPaper ivory={ivory} accent={theme.accent} />

        {/* flap */}
        <div className="absolute inset-x-0 top-0" style={{ height: '54%', perspective: 1700, perspectiveOrigin: '50% 0%', zIndex: opening ? 1 : 6 }}>
          <motion.div
            className="absolute inset-0"
            style={{
              transformOrigin: '50% 0%', transformStyle: 'preserve-3d',
              clipPath: 'polygon(0 0, 100% 0, 50% 100%)',
              background: `linear-gradient(176deg, ${shade(ivory, 0.07)} 0%, ${shade(ivory, 0.02)} 58%, ${shade(ivory, -0.06)} 100%)`,
              filter: `drop-shadow(0 3px 5px ${hexA('#000', 0.16)})`,
            }}
            animate={opening ? { rotateX: 176 } : { rotateX: 0 }}
            transition={{ duration: 0.72, ease: [0.4, 0, 0.2, 1] }}
          >
            {/* highlight along the two flap edges + centre crease */}
            <svg className="absolute inset-0 h-full w-full" viewBox="0 0 100 100" preserveAspectRatio="none" aria-hidden>
              <path d="M0 0 L50 100 L100 0" fill="none" stroke={hexA('#fff', 0.45)} strokeWidth="0.4" vectorEffect="non-scaling-stroke" />
            </svg>
            <div className="absolute left-1/2 top-0 h-full" style={{ width: 1, background: hexA('#000', 0.05) }} />
          </motion.div>
        </div>
      </motion.div>

      <Greeting theme={theme} names={names} fade={opening ? 0 : 1} />

      {/* the wax seal — click or drag down to open */}
      {!opening && (
        <SealButton onOpen={finish} mono={mono} font={theme.font} reduced={!!reduced} />
      )}

      <Hint dir="down" label={reduced ? 'Tap the seal to open' : 'Press the seal to open'} show={!opening} />
    </div>
  )
}

// the seal sits where the flap point meets the body; supports click + drag-down
function SealButton({ onOpen, mono, font, reduced }: { onOpen: () => void; mono: string[]; font: string; reduced: boolean }) {
  const y = useMotionValue(0)
  return (
    <motion.button
      type="button"
      drag={reduced ? false : 'y'}
      dragConstraints={{ top: 0, bottom: 150 }}
      dragElastic={0.16}
      style={{ y, position: 'absolute', left: '50%', top: '52%', x: '-50%', translateY: '-50%', zIndex: 20, touchAction: 'none', cursor: 'pointer' }}
      whileHover={reduced ? {} : { scale: 1.035 }}
      whileTap={{ scale: 0.97 }}
      onClick={onOpen}
      onDragEnd={(_e, info) => { if (info.offset.y > 80) onOpen(); else animate(y, 0, { type: 'spring', stiffness: 300, damping: 26 }) }}
      aria-label="Open the invitation"
    >
      <RealisticSeal mono={mono} size={186} font={font} />
    </motion.button>
  )
}

// Ivory stationery: warm paper, subtle botanical emboss, gold corner flourishes, vignette.
function BotanicalPaper({ ivory, accent }: { ivory: string; accent: string }) {
  return (
    <div className="absolute inset-0" style={{ background: `radial-gradient(120% 90% at 50% 0%, ${shade(ivory, -0.03)} 0%, ${ivory} 45%, ${shade(ivory, 0.05)} 100%)` }}>
      {/* fine paper grain */}
      <svg className="absolute inset-0 h-full w-full" aria-hidden style={{ opacity: 0.5, mixBlendMode: 'multiply' }}>
        <filter id="paperGrain"><feTurbulence type="fractalNoise" baseFrequency="0.82" numOctaves="2" seed="4" /><feColorMatrix type="matrix" values="0 0 0 0 0.42  0 0 0 0 0.35  0 0 0 0 0.24  0 0 0 0.05 0" /></filter>
        <rect width="100%" height="100%" filter="url(#paperGrain)" />
      </svg>
      {/* embossed botanical pattern */}
      <svg className="absolute inset-0 h-full w-full" aria-hidden preserveAspectRatio="xMidYMid slice" viewBox="0 0 400 400">
        <defs>
          <pattern id="bot" width="120" height="150" patternUnits="userSpaceOnUse" patternTransform="rotate(8)">
            <g fill="none" strokeWidth="1.4">
              {/* deboss = dark line + offset light line */}
              <g stroke={hexA('#000', 0.05)} transform="translate(0 1)">
                <path d="M20 130 C40 110 40 70 22 40 M22 40 C8 56 6 80 20 96 M22 64 C36 60 46 70 46 86 M22 88 C8 86 0 98 0 112" />
                <path d="M90 20 C108 36 110 70 96 100 M96 64 C82 60 72 70 72 86 M96 88 C112 86 120 100 120 112" />
              </g>
              <g stroke={hexA('#fff', 0.5)}>
                <path d="M20 130 C40 110 40 70 22 40 M22 40 C8 56 6 80 20 96 M22 64 C36 60 46 70 46 86 M22 88 C8 86 0 98 0 112" />
                <path d="M90 20 C108 36 110 70 96 100 M96 64 C82 60 72 70 72 86 M96 88 C112 86 120 100 120 112" />
              </g>
            </g>
          </pattern>
        </defs>
        <rect width="400" height="400" fill="url(#bot)" opacity="0.6" />
      </svg>

      {/* envelope body seams — bottom V flaps so the closed envelope reads */}
      <svg className="absolute inset-0 h-full w-full" viewBox="0 0 100 100" preserveAspectRatio="none" aria-hidden>
        <path d="M0 100 L50 56 L100 100" fill={hexA('#000', 0.025)} stroke={hexA('#000', 0.05)} strokeWidth="0.3" vectorEffect="non-scaling-stroke" />
        <path d="M0 0 L50 56 L0 100" fill={hexA('#000', 0.018)} />
        <path d="M100 0 L50 56 L100 100" fill={hexA('#000', 0.018)} />
      </svg>

      {/* gold corner flourishes (bottom corners, like fine stationery) */}
      {([['l', 'translate(28 372) scale(1,1)'], ['r', 'translate(372 372) scale(-1,1)']] as const).map(([k, tr]) => (
        <svg key={k} className="absolute" style={{ left: 0, top: 0, width: '100%', height: '100%' }} viewBox="0 0 400 400" aria-hidden>
          <g transform={tr} stroke={accent} strokeOpacity="0.5" strokeWidth="1.3" fill="none" strokeLinecap="round">
            <path d="M0 0 C18 -4 30 -16 34 -36 M10 -8 C8 -22 16 -32 30 -34 M0 0 C-2 -16 6 -26 18 -28" />
            <path d="M30 -34 C40 -30 44 -20 40 -10" />
            <circle cx="33" cy="-37" r="2" fill={accent} fillOpacity="0.6" stroke="none" />
          </g>
        </svg>
      ))}

      {/* soft vignette */}
      <div className="absolute inset-0" style={{ background: 'radial-gradient(120% 100% at 50% 42%, transparent 55%, rgba(40,28,10,0.16) 100%)' }} />
    </div>
  )
}

// ════════════════════════════════════════════════════════════════════════════════
// THE GATES — drag a handle sideways to pull both leaves apart; they swing open
// onto the film.
// ════════════════════════════════════════════════════════════════════════════════
export function GatesOpener({ theme, names, onOpen, videoSrc, poster }: OpenerProps) {
  const reduced = useReducedMotion()
  const [opening, setOpening] = useState(false)
  const mono = initials(names)
  const x = useMotionValue(0)
  const leftRot = useTransform(x, [0, 140], [0, -100])
  const rightRot = useTransform(x, [0, 140], [0, 100])
  const dim = useTransform(x, [0, 140], [0.4, 0.08])
  const greetFade = useTransform(x, [0, 80], [1, 0])
  const bloom = useTransform(x, [0, 140], [0.2, 0.95])

  const finish = () => {
    if (opening) return
    setOpening(true)
    animate(leftRot, -108, { duration: 0.8, ease: [0.5, 0, 0.2, 1] })
    animate(rightRot, 108, { duration: 0.8, ease: [0.5, 0, 0.2, 1] })
    animate(dim, 0, { duration: 0.8 })
    setTimeout(onOpen, 820)
  }

  return (
    <div className="absolute inset-0 overflow-hidden">
      <FilmBackdropMV videoSrc={videoSrc} poster={poster} dim={dim} />
      <motion.div className="absolute left-1/2 top-1/2 z-10 -translate-x-1/2 -translate-y-1/2" style={{ width: 460, height: 460, borderRadius: '50%', background: `radial-gradient(circle, ${hexA(theme.accent, 0.5)} 0%, transparent 66%)`, filter: 'blur(28px)', opacity: bloom }} />
      <Greeting theme={theme} names={names} fade={reduced ? 1 : greetFade} />

      <div className="absolute inset-0 flex items-center justify-center" style={{ perspective: 1500 }}>
        <div className="relative" style={{ width: 'min(88vw, 440px)', height: 'min(74vh, 500px)' }}>
          {(['l', 'r'] as const).map((s) => (
            <motion.div key={s} className="absolute top-0 bottom-0" style={{ width: '50%', [s === 'l' ? 'left' : 'right']: 0, transformOrigin: s === 'l' ? 'left center' : 'right center', transformStyle: 'preserve-3d', backfaceVisibility: 'hidden', rotateY: s === 'l' ? leftRot : rightRot, filter: `drop-shadow(0 14px 26px ${hexA('#000', 0.5)})` }}>
              <GateLeaf side={s} accent={theme.accent} ink={theme.ink} />
            </motion.div>
          ))}
          {/* draggable center crest (realistic gold seal) */}
          {!opening && (
            <motion.button type="button"
              drag={reduced ? false : 'x'} dragConstraints={{ left: 0, right: 150 }} dragElastic={0.16}
              style={{ x, left: '50%', top: '50%', translateX: '-50%', translateY: '-50%', position: 'absolute', zIndex: 20, touchAction: 'none', cursor: 'pointer' }}
              whileHover={reduced ? {} : { scale: 1.04 }}
              whileTap={{ scale: 0.97 }}
              onClick={finish}
              onDragEnd={(_e, info) => { if (info.offset.x > 90) finish(); else animate(x, 0, { type: 'spring', stiffness: 280, damping: 26 }) }}
              aria-label="Open the gates">
              <RealisticSeal mono={mono} size={108} font={theme.font} rose={false} />
            </motion.button>
          )}
        </div>
      </div>

      <Hint dir="apart" label={reduced ? 'Tap to open the gates' : 'Pull the gates apart'} show={!opening} />
    </div>
  )
}

function GateLeaf({ side, accent, ink }: { side: 'l' | 'r'; accent: string; ink: string }) {
  const W = 180, H = 380
  const bars = [30, 64, 98, 132, 166].map((bx) => (side === 'l' ? bx : W - bx))
  const iron = shade(ink, -0.12)
  const gid = `g-${side}`
  return (
    <svg viewBox={`0 0 ${W} ${H}`} width="100%" height="100%" preserveAspectRatio="none" aria-hidden>
      <defs><linearGradient id={gid} x1="0" y1="0" x2="1" y2="1"><stop offset="0%" stopColor={shade(accent, -0.25)} /><stop offset="45%" stopColor={accent} /><stop offset="100%" stopColor={shade(accent, 0.35)} /></linearGradient></defs>
      <rect x="6" y="6" width={W - 12} height={H - 12} fill={hexA('#0d0d0f', 0.34)} stroke={iron} strokeWidth="7" />
      <rect x="6" y="6" width={W - 12} height={H - 12} fill="none" stroke={`url(#${gid})`} strokeWidth="2" />
      {bars.map((bx, i) => (
        <g key={i}>
          <line x1={bx} y1="40" x2={bx} y2={H - 16} stroke={iron} strokeWidth="4.5" />
          <line x1={bx} y1="40" x2={bx} y2={H - 16} stroke={`url(#${gid})`} strokeWidth="1.4" />
          <path d={`M${bx - 7} 40 L${bx} 18 L${bx + 7} 40 Z`} fill={iron} stroke={`url(#${gid})`} strokeWidth="1" />
        </g>
      ))}
      {[120, 250].map((yy, i) => (<g key={i}><line x1="14" y1={yy} x2={W - 14} y2={yy} stroke={iron} strokeWidth="6" /><line x1="14" y1={yy} x2={W - 14} y2={yy} stroke={`url(#${gid})`} strokeWidth="1.6" /></g>))}
      {bars.slice(0, -1).map((bx, i) => { const nx = bars[i + 1]; const mx = (bx + nx) / 2; return (<g key={i} stroke={`url(#${gid})`} strokeWidth="2.2" fill="none" opacity="0.85"><path d={`M${bx} 168 C${bx} 150 ${mx} 150 ${mx} 178 C${mx} 150 ${nx} 150 ${nx} 168`} /><path d={`M${bx} 202 C${bx} 220 ${mx} 220 ${mx} 192 C${mx} 220 ${nx} 220 ${nx} 202`} /></g>) })}
    </svg>
  )
}

// ════════════════════════════════════════════════════════════════════════════════
// THE VEIL — drag the sheer fabric UP to lift it off the film.
// ════════════════════════════════════════════════════════════════════════════════
export function VeilOpener({ theme, names, onOpen, videoSrc, poster }: OpenerProps) {
  const reduced = useReducedMotion()
  const [opening, setOpening] = useState(false)
  const y = useMotionValue(0)
  const veilY = useTransform(y, [-260, 0], ['-100%', '0%'])
  const veilOpacity = useTransform(y, [-260, -40, 0], [0, 0.85, 1])
  const dim = useTransform(y, [-260, 0], [0.06, 0.4])
  const greetFade = useTransform(y, [-140, 0], [0, 1])

  const finish = () => {
    setOpening(true)
    animate(y, -560, { duration: 1, ease: [0.4, 0, 0.2, 1] })
    animate(dim, 0, { duration: 0.8 })
    setTimeout(onOpen, 980)
  }

  return (
    <div className="absolute inset-0 overflow-hidden">
      <FilmBackdropMV videoSrc={videoSrc} poster={poster} dim={dim} />
      <Greeting theme={theme} names={names} fade={reduced ? 1 : greetFade} />

      {/* draggable veil */}
      {!opening && (
        <motion.button type="button"
          drag={reduced ? false : 'y'} dragConstraints={{ top: -260, bottom: 0 }} dragElastic={0.12}
          style={{ y, position: 'absolute', inset: 0, zIndex: 20, touchAction: 'none', cursor: 'grab' }}
          whileTap={{ cursor: 'grabbing' }}
          onClick={() => { if (reduced) finish() }}
          onDragEnd={(_e, info) => { if (info.offset.y < -90) finish(); else animate(y, 0, { type: 'spring', stiffness: 240, damping: 28 }) }}
          aria-label="Lift the veil">
          <motion.div className="absolute inset-x-[-12%] top-[-8%]" style={{ height: '122%', y: veilY, opacity: veilOpacity,
            background: `linear-gradient(180deg, ${hexA('#ffffff', theme.dark ? 0.14 : 0.6)} 0%, ${hexA('#ffffff', theme.dark ? 0.05 : 0.28)} 62%, transparent 100%)`,
            backdropFilter: 'blur(7px)', WebkitBackdropFilter: 'blur(7px)' }}>
            {/* lace hem */}
            <svg className="absolute left-0 right-0" style={{ bottom: -1, width: '100%', height: 26 }} viewBox="0 0 400 26" preserveAspectRatio="none" aria-hidden>
              <path d="M0 0 H400 V8 Q390 26 380 8 Q370 26 360 8 Q350 26 340 8 Q330 26 320 8 Q310 26 300 8 Q290 26 280 8 Q270 26 260 8 Q250 26 240 8 Q230 26 220 8 Q210 26 200 8 Q190 26 180 8 Q170 26 160 8 Q150 26 140 8 Q130 26 120 8 Q110 26 100 8 Q90 26 80 8 Q70 26 60 8 Q50 26 40 8 Q30 26 20 8 Q10 26 0 8 Z" fill={hexA('#ffffff', theme.dark ? 0.16 : 0.6)} />
            </svg>
          </motion.div>
        </motion.button>
      )}

      <Hint dir="up" label={reduced ? 'Tap to lift the veil' : 'Lift the veil'} show={!opening} />
    </div>
  )
}

// motion-value-driven backdrop (dim is a MotionValue)
function FilmBackdropMV({ videoSrc, poster, dim }: { videoSrc?: string | null; poster?: string | null; dim: MotionValue<number> }) {
  return (
    <div className="absolute inset-0">
      <div className="absolute inset-0" style={{ background: poster ? `center/cover url(${poster})` : '#111', backgroundColor: '#111' }} />
      {videoSrc && <video className="absolute inset-0 h-full w-full object-cover" src={videoSrc} poster={poster ?? undefined} autoPlay muted loop playsInline />}
      <motion.div className="absolute inset-0" style={{ background: '#0b0b0d', opacity: dim }} />
    </div>
  )
}
