const W = 148
const H = Math.round(W * 16 / 9)

function Corner({ color, deg }: { color: string; deg: number }) {
  return (
    <svg
      viewBox="0 0 14 14"
      width="11"
      height="11"
      style={{ transform: `rotate(${deg}deg)` }}
      aria-hidden="true"
    >
      <path d="M0,0 L10,0 L10,1.8 L1.8,1.8 L1.8,10 L0,10 Z" fill={color} opacity="0.55" />
    </svg>
  )
}

function Divider({ color }: { color: string }) {
  return (
    <svg viewBox="0 0 52 10" width="48" height="9" aria-hidden="true">
      <line x1="0"  y1="4.5" x2="19" y2="4.5" stroke={color} strokeWidth="0.5" opacity="0.55" />
      <rect x="23" y="1.5"   width="5.5" height="5.5" transform="rotate(45 25.75 4.25)" fill={color} opacity="0.55" />
      <line x1="32" y1="4.5" x2="52" y2="4.5" stroke={color} strokeWidth="0.5" opacity="0.55" />
    </svg>
  )
}

function Card({ c }: { c: CardDef }) {
  return (
    <div
      style={{
        width: W,
        height: H,
        flexShrink: 0,
        borderRadius: 4,
        boxShadow: '0 8px 32px rgba(0,0,0,0.18), 0 2px 6px rgba(0,0,0,0.10)',
        position: 'relative',
        overflow: 'hidden',
        marginRight: 13,
      }}
    >
      {/* Wedding photo background */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          backgroundImage: `url(${c.photo})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          zIndex: 0,
        }}
      />
      {/* Theme color overlay */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          background: c.bg,
          opacity: 0.72,
          zIndex: 1,
        }}
      />

      {/* Card content */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          zIndex: 2,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '20px 14px',
        }}
      >
        {/* Corners */}
        <div style={{ position: 'absolute', top: 9,  left: 9  }}><Corner color={c.accent} deg={0}   /></div>
        <div style={{ position: 'absolute', top: 9,  right: 9 }}><Corner color={c.accent} deg={90}  /></div>
        <div style={{ position: 'absolute', bottom: 9, left: 9  }}><Corner color={c.accent} deg={270} /></div>
        <div style={{ position: 'absolute', bottom: 9, right: 9 }}><Corner color={c.accent} deg={180} /></div>

        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 7, textAlign: 'center', width: '100%' }}>
          <span style={{ fontFamily: 'var(--font-inter)', fontSize: 6, letterSpacing: '0.28em', textTransform: 'uppercase', color: c.fg, opacity: 0.38 }}>
            You are invited
          </span>

          <Divider color={c.accent} />

          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 0 }}>
            <span style={{ fontFamily: 'var(--font-cormorant)', fontSize: 20, fontWeight: 300, color: c.fg, lineHeight: 1.15 }}>
              {c.name1}
            </span>
            <span style={{ fontFamily: 'var(--font-cormorant)', fontSize: 13, fontStyle: 'italic', color: c.accent, lineHeight: 1.4 }}>
              &amp;
            </span>
            <span style={{ fontFamily: 'var(--font-cormorant)', fontSize: 20, fontWeight: 300, color: c.fg, lineHeight: 1.15 }}>
              {c.name2}
            </span>
          </div>

          <Divider color={c.accent} />

          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 3 }}>
            <span style={{ fontFamily: 'var(--font-inter)', fontSize: 6.5, letterSpacing: '0.2em', color: c.fg, opacity: 0.48 }}>
              {c.date}
            </span>
            <span style={{ fontFamily: 'var(--font-inter)', fontSize: 6, letterSpacing: '0.1em', color: c.fg, opacity: 0.3 }}>
              {c.loc}
            </span>
          </div>
        </div>
      </div>
    </div>
  )
}

function Row({
  cards,
  reverse,
  duration,
}: {
  cards: CardDef[]
  reverse: boolean
  duration: number
}) {
  const reduced = useReducedMotion()
  const anim = reverse ? 'marquee-x-rev' : 'marquee-x'

  const innerStyle: CSSProperties = {
    display: 'flex',
    willChange: 'transform',
    animation: reduced ? 'none' : `${anim} ${duration}s linear infinite`,
  }

  const doubled = [...cards, ...cards]

  return (
    <div style={{ overflow: 'hidden', display: 'flex' }}>
      <div style={innerStyle}>
        {doubled.map((c, i) => (
          <Card key={`${c.id}-${i}`} c={c} />
        ))}
      </div>
    </div>
  )
}

export function MarqueeCards() {
  const reversed = [...CARDS].reverse()

  return (
    <div
      style={{
        display: 'flex',
        flexDirection: 'column',
        gap: 12,
        userSelect: 'none',
        pointerEvents: 'none',
      }}
    >
      <Row cards={CARDS}    reverse={false} duration={55} />
      <Row cards={reversed} reverse={true}  duration={44} />
    </div>
  )
}
